if (!String(result).trim()) {
  result = "未获取到文本，可能被验证拦截，请刷新正文或手动过盾。";
} else {
  let doc = org.jsoup.Jsoup.parse(String(result));
  doc.select("h1, script, style, #txtright, .txtinfo, .contentadv, .bottom-ad").remove();
  result = String(doc.body().html());
  result = result.replace(/\(本章完\)|\ue5e5/g, '');
}
result;

